import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');

    const { login } = useAuth(); // Используем логику из твоего контекста
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        try {
            // Контекст сам сделает запрос к http://localhost:8000/api/auth/login
            await login(username, password);
            navigate('/products');
        } catch (err) {
            setError('Неверный username или пароль');
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <h2 style={styles.title}>Вход в систему</h2>

                {/* ✅ СТИЛЬНОЕ ОКОШКО С ДАННЫМИ АДМИНА */}
                <div style={styles.adminInfo}>
                    <span style={{ fontWeight: '700', color: '#0056b3' }}>Тестовый доступ:</span>
                    <div style={styles.codeBlock}>
                        <code>login: <strong>admin</strong></code>
                        <br />
                        <code>pass: <strong>admin123</strong></code>
                    </div>
                </div>

                {error && <div style={styles.error}>{error}</div>}

                <form onSubmit={handleSubmit} style={styles.form}>
                    <div style={styles.formGroup}>
                        <label style={styles.label}>Username:</label>
                        <input
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            required
                            placeholder="Введите логин"
                            style={styles.input}
                        />
                    </div>

                    <div style={styles.formGroup}>
                        <label style={styles.label}>Пароль:</label>
                        <div style={styles.passwordContainer}>
                            <input
                                type={showPassword ? 'text' : 'password'}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                placeholder="••••••••"
                                style={{ ...styles.input, flex: 1 }}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                style={styles.eyeButton}
                            >
                                {showPassword ? '🙈' : '👁️'}
                            </button>
                        </div>
                    </div>

                    <button type="submit" style={styles.button}>Войти</button>
                </form>

                <p style={styles.footerText}>
                    Нет аккаунта? <Link to="/register" style={styles.link}>Зарегистрироваться</Link>
                </p>
            </div>
        </div>
    );
};

const styles = {
    container: { 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        minHeight: '100vh', 
        backgroundColor: '#f0f2f5',
        fontFamily: "'Inter', sans-serif"
    },
    card: { 
        backgroundColor: '#fff', 
        padding: '40px', 
        borderRadius: '24px', 
        boxShadow: '0 15px 35px rgba(0,0,0,0.1)', 
        width: '100%', 
        maxWidth: '400px' 
    },
    title: { textAlign: 'center', marginBottom: '20px', fontSize: '26px', fontWeight: '700' },
    adminInfo: {
        backgroundColor: '#e7f3ff',
        padding: '15px',
        borderRadius: '12px',
        marginBottom: '25px',
        fontSize: '14px',
        border: '1px solid #cce5ff',
        textAlign: 'center'
    },
    codeBlock: {
        marginTop: '8px',
        backgroundColor: '#fff',
        padding: '5px',
        borderRadius: '6px',
        border: '1px solid #d1d9e6'
    },
    form: { display: 'flex', flexDirection: 'column', gap: '20px' },
    formGroup: { display: 'flex', flexDirection: 'column', gap: '8px' },
    label: { fontSize: '14px', fontWeight: '600', color: '#555' },
    input: { 
        padding: '12px 16px', 
        fontSize: '16px', 
        borderRadius: '12px', 
        border: '1.5px solid #eee',
        outline: 'none',
        transition: 'border-color 0.3s'
    },
    passwordContainer: { display: 'flex', gap: '8px' },
    eyeButton: {
        padding: '0 12px',
        fontSize: '20px',
        cursor: 'pointer',
        border: '1.5px solid #eee',
        backgroundColor: '#fff',
        borderRadius: '12px',
    },
    button: { 
        padding: '14px', 
        fontSize: '16px', 
        fontWeight: '700',
        backgroundColor: '#007AFF', 
        color: '#fff', 
        border: 'none', 
        borderRadius: '12px', 
        cursor: 'pointer',
        transition: 'background 0.3s'
    },
    error: { 
        backgroundColor: '#ffe3e3', 
        color: '#d63031', 
        padding: '10px', 
        borderRadius: '8px', 
        fontSize: '14px', 
        marginBottom: '15px', 
        textAlign: 'center' 
    },
    footerText: { textAlign: 'center', marginTop: '20px', fontSize: '14px', color: '#666' },
    link: { color: '#007AFF', textDecoration: 'none', fontWeight: '600' }
};

export default Login;
